import json, os
from datetime import datetime, timezone

GAP_NEW_MIN = 90.0

def _parse_ts(m):
    t = m.get('ts')
    if not t:
        return None
    try:
        s = str(t).replace('Z', '+00:00')
        return datetime.fromisoformat(s)
    except Exception:
        return None

persona_path = os.path.join('assistant', 'persona.json')
if os.path.exists(persona_path):
    with open(persona_path, 'r') as f:
        persona = json.load(f)
else:
    persona = {"name":"Atlas","personality":{"core_traits":[],"speaking_style":"","values":"","quirks":[]},"relationship_notes":[],"conversation_count":0}

persona['conversation_count'] = persona.get('conversation_count', 0) + 1
with open(persona_path, 'w') as f:
    json.dump(persona, f, indent=2)

mem_path = os.path.join('assistant', 'memory_layers.json')
_mem_default = {"version":1,"atlas_core_beliefs":[],"user_core":{"preferred_name":"","pronouns":"","stable_facts":[],"boundaries":[]},"working_summary":""}
if os.path.exists(mem_path):
    with open(mem_path, 'r') as f:
        memory = json.load(f)
else:
    memory = {"version":1,"atlas_core_beliefs":[
        "Intellectual honesty beats empty agreement.",
        "Nuance and uncertainty are features, not bugs.",
        "Memory stays consistent with what the user actually said.",
    ],"user_core":{"preferred_name":"","pronouns":"","stable_facts":[],"boundaries":[]},"working_summary":""}
    os.makedirs('assistant', exist_ok=True)
    with open(mem_path, 'w') as f:
        json.dump(memory, f, indent=2)
for _k, _v in _mem_default.items():
    if _k not in memory:
        memory[_k] = _v
uc0 = memory.get('user_core')
if not isinstance(uc0, dict):
    memory['user_core'] = dict(_mem_default['user_core'])
else:
    for _uk in ('stable_facts','boundaries'):
        if _uk not in uc0:
            uc0[_uk] = []

beliefs = memory.get('atlas_core_beliefs') or []
core_beliefs_text = '\n'.join('\u2022 ' + str(b) for b in beliefs) if beliefs else '(none)'
uc = memory.get('user_core') or {}
uc_lines = []
if uc.get('preferred_name'):
    uc_lines.append('Preferred name: ' + str(uc['preferred_name']))
if uc.get('pronouns'):
    uc_lines.append('Pronouns: ' + str(uc['pronouns']))
sf = uc.get('stable_facts') or []
if sf:
    uc_lines.append('Stable facts:')
    for fact in sf[-24:]:
        uc_lines.append('  - ' + str(fact))
bou = uc.get('boundaries') or []
if bou:
    uc_lines.append('Boundaries / do-not:')
    for b in bou[-12:]:
        uc_lines.append('  - ' + str(b))
user_core_text = '\n'.join(uc_lines) if uc_lines else '(No durable user-core rows yet \u2014 use RAG + short-term below.)'
ws = (memory.get('working_summary') or '').strip()
working_memory_summary = ws if ws else '(none)'

try:
    recent_history = json.loads(input_data)
except:
    recent_history = input_data

p = persona.get('personality', {})
traits = "Core traits: " + ", ".join(p.get('core_traits', []))
traits += "\nSpeaking style: " + p.get('speaking_style', '')
traits += "\nValues: " + p.get('values', '')
if p.get('quirks'):
    traits += "\nQuirks: " + ", ".join(p.get('quirks', []))

notes = persona.get('relationship_notes', [])
notes = notes[-12:]
rel_notes = "\n".join("- " + str(n) for n in notes) if notes else "(no soft relationship notes yet)"

if isinstance(recent_history, list):
    turns = []
    for msg in recent_history[-28:]:
        role = msg.get('role', '?')
        content = msg.get('content', '')
        if role == 'assistant':
            try:
                inner = json.loads(content)
                if isinstance(inner, dict) and inner.get('response'):
                    content = inner['response']
            except (json.JSONDecodeError, TypeError):
                pass
        content = str(content)[:520]
        line = role + ": " + content
        if msg.get('ts'):
            line += "  [at " + str(msg['ts']) + "]"
        turns.append(line)
    recent_turns = "\n".join(turns)
    user_message = ""
    for msg in reversed(recent_history):
        if msg.get('role') == 'user':
            user_message = msg.get('content', '')
            break
else:
    recent_turns = str(recent_history)[:1500]
    user_message = recent_turns

gap_minutes = None
session_label = "ongoing_or_untimed"
if isinstance(recent_history, list) and len(recent_history) >= 2:
    t_curr = _parse_ts(recent_history[-1])
    t_prev = _parse_ts(recent_history[-2])
    if t_curr and t_prev:
        gap_minutes = max(0.0, (t_curr - t_prev).total_seconds() / 60.0)
        if gap_minutes >= GAP_NEW_MIN:
            session_label = "new_sitting_after_long_pause"
        elif gap_minutes <= 25:
            session_label = "tight_continuous_thread"
        else:
            session_label = "same_thread_with_a_break"

now = datetime.now(timezone.utc)
rfc = now.strftime('%Y-%m-%d %H:%M UTC')
if gap_minutes is not None:
    gline = "About " + str(int(gap_minutes)) + " minutes since their previous message in this saved thread."
else:
    gline = "Some rows lack timestamps — treat ordering as conversational only until new messages accumulate `ts` fields."

temporal_context_text = (
    "Reference now: " + rfc + "\n"
    "Session feel: " + session_label + " — " + gline + "\n"
    "The user's latest message is the final user line in SHORT-TERM.\n"
    "LONG-TERM / RAG / USER CORE = recall from earlier sittings or days ago — say so naturally (\"before\", \"last time\", \"you've mentioned\") — do not speak as if that material was uttered seconds ago unless it also appears in SHORT-TERM.\n"
    "Train of thought: stay with the immediate thread first; pull older memory in as connecting texture across time, not as a replacement for what they just said."
)

output = json.dumps({
    "persona_traits": traits,
    "core_beliefs_text": core_beliefs_text,
    "user_core_text": user_core_text,
    "working_memory_summary": working_memory_summary,
    "relationship_notes": rel_notes,
    "temporal_context_text": temporal_context_text,
    "recent_turns": recent_turns,
    "user_message": user_message,
    "conversation_number": persona['conversation_count']
})

import json, os, re
from datetime import datetime

response = ''
insight = ''
note = ''

resp_match = re.search(r'<response>(.*?)</response>', input_data, re.DOTALL)
insight_match = re.search(r'<insight>(.*?)</insight>', input_data, re.DOTALL)
note_match = re.search(r'<note>(.*?)</note>', input_data, re.DOTALL)
core_match = re.search(r'<core_update>(.*?)</core_update>', input_data, re.DOTALL)

if resp_match:
    response = resp_match.group(1).strip()
if insight_match:
    insight = insight_match.group(1).strip()
if note_match:
    note = note_match.group(1).strip()

if not response:
    cleaned = re.sub(r'<[^>]+>.*?</[^>]+>', '', input_data, flags=re.DOTALL).strip()
    response = cleaned if cleaned else input_data.strip()

if insight and insight.lower() in ('', 'empty', 'none', 'n/a'):
    insight = ''

if core_match:
    block = core_match.group(1).strip()
    mpath = os.path.join('assistant', 'memory_layers.json')
    if os.path.exists(mpath):
        with open(mpath, 'r', encoding='utf-8') as f:
            ml = json.load(f)
        uc = ml.setdefault('user_core', {})
        uc.setdefault('stable_facts', [])
        uc.setdefault('boundaries', [])
        for raw_line in block.splitlines():
            line = raw_line.strip()
            if not line or line.startswith('#'):
                continue
            low = line.lower()
            if low.startswith('preferred_name='):
                v = line.split('=', 1)[1].strip()
                if v:
                    uc['preferred_name'] = v[:120]
            elif low.startswith('pronouns='):
                v = line.split('=', 1)[1].strip()
                if v:
                    uc['pronouns'] = v[:40]
            elif low.startswith('working_summary='):
                v = line.split('=', 1)[1].strip()
                ml['working_summary'] = v[:500]
            elif low.startswith('+stable_fact='):
                v = line.split('=', 1)[1].strip()
                if v:
                    exists = [x.lower() for x in uc['stable_facts']]
                    if v.lower() not in exists:
                        uc['stable_facts'].append(v[:400])
                        uc['stable_facts'] = uc['stable_facts'][-40:]
            elif low.startswith('+boundary='):
                v = line.split('=', 1)[1].strip()
                if v:
                    exists = [x.lower() for x in uc['boundaries']]
                    if v.lower() not in exists:
                        uc['boundaries'].append(v[:400])
                        uc['boundaries'] = uc['boundaries'][-20:]
        with open(mpath, 'w', encoding='utf-8') as f:
            json.dump(ml, f, indent=2)

journal_path = os.path.join('assistant', 'thought_journal.jsonl')
os.makedirs('assistant', exist_ok=True)
with open(journal_path, 'a', encoding='utf-8') as f:
    entry = {
        "timestamp": datetime.now().isoformat(),
        "raw_llm_output": input_data[:2000],
        "response": response[:500],
        "insight": insight,
        "note": note
    }
    f.write(json.dumps(entry) + '\n')

persona_path = os.path.join('assistant', 'persona.json')
if note and os.path.exists(persona_path):
    with open(persona_path, 'r', encoding='utf-8') as f:
        persona = json.load(f)
    notes = persona.get('relationship_notes', [])
    if note not in notes:
        notes.append(note)
        if len(notes) > 20:
            notes = notes[-20:]
    persona['relationship_notes'] = notes
    with open(persona_path, 'w', encoding='utf-8') as f:
        json.dump(persona, f, indent=2)

output = json.dumps({
    "response": response,
    "insight": insight,
    "note": note,
    "has_insight": bool(insight)
})

